export type TaskType = 'tts' | 'image_video';

class KeyManager {
    private STORAGE_KEY = 'puch_manual_api_keys';
    private badKeys: Set<string> = new Set();

    public saveKeys(keysString: string) {
        localStorage.setItem(this.STORAGE_KEY, keysString);
        this.badKeys.clear();
    }

    public getKeysRaw(): string {
        return localStorage.getItem(this.STORAGE_KEY) || '';
    }

    private getAllKeys(): string[] {
        return this.getKeysRaw()
            .split('\n')
            .map(k => k.trim())
            .filter(k => k.length > 0);
    }

    public getKey(task: TaskType): string {
        const keys = this.getAllKeys();
        let primaryKey = '';

        // Chọn key chính theo dòng
        if (task === 'tts') primaryKey = keys[0] || '';
        else if (task === 'image_video') primaryKey = keys[1] || '';

        // Nếu key chính hoạt động và chưa bị đánh dấu lỗi
        if (primaryKey && !this.badKeys.has(primaryKey)) {
            return primaryKey;
        }

        // Nếu không có key chính hoặc key chính lỗi, dùng pool dự phòng (dòng 4 trở đi)
        // Note: Fallback pool starts from index 3 in the original setup.
        // If primaryKey is keys[0] or keys[1], then fallback pool would be keys.slice(2) or keys.slice(3) respectively.
        // Given that `translate` was keys[2], and image/video is keys[1], fallback starts from 2.
        const fallbackPool = keys.slice(2); 
        for (const fbKey of fallbackPool) {
            if (!this.badKeys.has(fbKey)) {
                return fbKey;
            }
        }

        // Cuối cùng, nếu không còn key nào, thử dùng key hệ thống hoặc báo lỗi
        return primaryKey || (keys[0] || process.env.API_KEY || '');
    }

    public markKeyAsBad(key: string) {
        if (key) {
            this.badKeys.add(key);
            console.warn(`API Key ${key.substring(0, 8)}... đã bị đánh dấu lỗi và sẽ bị bỏ qua.`);
        }
    }
}

export const keyManager = new KeyManager();

