thêm mục lọc <!DOCTYPE html>
<html lang="vi">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Text Filter Pro - Công cụ lọc chữ chuyên nghiệp</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <style>
        body {
            background-color: #f8fafc;
            font-family: 'Inter', system-ui, -apple-system, sans-serif;
        }
        .glass-card {
            background: rgba(255, 255, 255, 0.95);
            backdrop-filter: blur(10px);
            border: 1px solid rgba(226, 232, 240, 0.8);
        }
    </style>
</head>
<body class="p-4 md:p-8">
    <div class="max-w-5xl mx-auto">
        <header class="mb-8 text-center">
            <h1 class="text-3xl font-bold text-slate-800 mb-2">Text Filter Tool</h1>
            <p class="text-slate-500">Công cụ xử lý và lọc văn bản nhanh chóng, bảo mật</p>
        </header>

        <div class="grid grid-cols-1 lg:grid-cols-3 gap-6">
            <!-- Cấu hình Lọc -->
            <div class="lg:col-span-1 space-y-4">
                <div class="glass-card p-6 rounded-2xl shadow-sm">
                    <h2 class="text-lg font-semibold mb-4 flex items-center">
                        <svg class="w-5 h-5 mr-2 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4"></path></svg>
                        Tùy chọn lọc
                    </h2>

                    <div class="space-y-3">
                        <label class="flex items-center space-x-3 text-sm text-slate-600 cursor-pointer">
                            <input type="checkbox" id="removeJunkBlocks" class="w-4 h-4 text-blue-600 rounded" checked>
                            <span class="font-medium text-blue-700">Lọc khối rác MXH (Liên tiếp)</span>
                        </label>

                        <label class="flex items-center space-x-3 text-sm text-slate-600 cursor-pointer">
                            <input type="checkbox" id="removeChapterHeader" class="w-4 h-4 text-orange-600 rounded" checked>
                            <span class="font-medium text-orange-700">Xóa tiêu đề Chapter/Chương</span>
                        </label>

                        <!-- Tính năng mới: Xóa số cuối dòng -->
                        <label class="flex items-center space-x-3 text-sm text-slate-600 cursor-pointer">
                            <input type="checkbox" id="removeEndNumbers" class="w-4 h-4 text-red-600 rounded" checked>
                            <span class="font-medium text-red-700">Xóa số lẻ/thông báo cuối dòng</span>
                        </label>
                        <p class="text-[10px] text-slate-400 ml-7 -mt-2">* Xóa số đơn lẻ như 1, 2, 99+ ở cuối mỗi dòng.</p>

                        <hr class="my-2 border-slate-100">

                        <label class="flex items-center space-x-3 text-sm text-slate-600 cursor-pointer">
                            <input type="checkbox" id="removeNumbers" class="w-4 h-4 text-blue-600 rounded">
                            <span>Loại bỏ TẤT CẢ số</span>
                        </label>
                        <label class="flex items-center space-x-3 text-sm text-slate-600 cursor-pointer">
                            <input type="checkbox" id="removeWhitespace" class="w-4 h-4 text-blue-600 rounded" checked>
                            <span>Xóa khoảng trắng thừa & dòng trống</span>
                        </label>
                    </div>

                    <div class="mt-6">
                        <label class="block text-sm font-medium text-slate-700 mb-2">Từ khóa rác liên tiếp</label>
                        <textarea id="junkKeywords" class="w-full p-3 text-sm border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none h-32">comment, 0 comment, Vote, SEND GIFT, bình luận, 0 bình luận, bỏ phiếu, gửi quà tặng, gửI quà tặng</textarea>
                    </div>
                </div>
            </div>

            <!-- Khu vực nhập liệu -->
            <div class="lg:col-span-2 space-y-6">
                <div class="glass-card p-6 rounded-2xl shadow-sm">
                    <label class="block text-sm font-medium text-slate-700 mb-2">Văn bản gốc</label>
                    <textarea id="inputText" placeholder="Dán văn bản vào đây..." class="w-full h-64 p-4 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none mb-4"></textarea>

                    <div class="flex flex-wrap gap-3">
                        <button onclick="processText()" class="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white font-semibold rounded-xl transition-all shadow-md shadow-blue-200">Xử lý ngay</button>
                        <button onclick="clearAll()" class="px-6 py-2 bg-white border border-slate-200 text-slate-600 hover:bg-slate-50 font-medium rounded-xl transition-all">Xóa hết</button>
                    </div>
                </div>

                <div class="glass-card p-6 rounded-2xl shadow-sm border-t-4 border-t-blue-500">
                    <div class="flex justify-between items-center mb-2">
                        <label class="text-sm font-medium text-slate-700">Kết quả</label>
                        <button onclick="copyResult()" class="text-blue-600 hover:text-blue-700 text-xs font-bold uppercase tracking-wider">Sao chép</button>
                    </div>
                    <div id="outputText" class="w-full min-h-[100px] p-4 bg-slate-50 border border-slate-100 rounded-xl text-slate-800 whitespace-pre-wrap break-words">Kết quả hiển thị tại đây...</div>
                </div>
            </div>
        </div>
    </div>

    <div id="toast" class="fixed bottom-8 left-1/2 -translate-x-1/2 px-6 py-3 bg-slate-800 text-white rounded-full text-sm font-medium opacity-0 transition-opacity pointer-events-none">
        Đã sao chép!
    </div>

    <script>
        function processText() {
            let text = document.getElementById('inputText').value;
            if (!text) return;

            let lines = text.split(/\r?\n/);
            const junkKeywords = document.getElementById('junkKeywords').value.split(',').map(k => k.trim().toLowerCase()).filter(k => k !== "");
            const removeJunk = document.getElementById('removeJunkBlocks').checked;
            const removeChapter = document.getElementById('removeChapterHeader').checked;
            const removeEndNums = document.getElementById('removeEndNumbers').checked;

            let finalLines = [];
            let i = 0;

            while (i < lines.length) {
                let line = lines[i];
                let lineTrimmed = line.trim();
                let lineLower = lineTrimmed.toLowerCase();

                // 1. Xóa Chapter/Chương
                if (removeChapter) {
                    const chapterPattern = /^(chapter|chương)\s+\d+/i;
                    if (chapterPattern.test(lineTrimmed)) {
                        i++;
                        continue;
                    }
                }

                // 2. Xóa khối rác liên tiếp (có tính đến dòng trống ở giữa)
                if (removeJunk) {
                    let isCurrentJunk = junkKeywords.some(k => lineLower === k || lineLower.includes(k));

                    if (isCurrentJunk) {
                        let nextJunkIdx = -1;
                        for (let j = i + 1; j < Math.min(i + 6, lines.length); j++) {
                            let nextLineLower = lines[j].trim().toLowerCase();
                            if (nextLineLower === "") continue; 
                            if (junkKeywords.some(k => nextLineLower === k || nextLineLower.includes(k))) {
                                nextJunkIdx = j;
                                break;
                            }
                        }

                        if (nextJunkIdx !== -1) {
                            while (i < lines.length) {
                                let checkLine = lines[i].trim().toLowerCase();
                                if (checkLine === "" || junkKeywords.some(k => checkLine === k || checkLine.includes(k))) {
                                    i++;
                                } else {
                                    break; 
                                }
                            }
                            continue;
                        }
                    }
                }

                // 3. Xóa số đơn lẻ ở cuối dòng (1, 2, 99, 99+)
                if (removeEndNums) {
                    // Regex này tìm số (có thể kèm dấu +) đứng ở cuối dòng sau khi đã có nội dung
                    // Ví dụ: "Nội dung câu văn 99" -> "Nội dung câu văn"
                    line = line.replace(/\s+\d+(\+)?\s*$/, '');
                }

                finalLines.push(line);
                i++;
            }

            let result = finalLines.join('\n');

            // Xóa toàn bộ số nếu được chọn
            if (document.getElementById('removeNumbers').checked) {
                result = result.replace(/[0-9]/g, '');
            }

            // Xóa khoảng trắng thừa và dòng trống
            if (document.getElementById('removeWhitespace').checked) {
                result = result.replace(/[^\S\r\n]+/g, ' ') 
                               .replace(/^\s*[\r\n]/gm, '') 
                               .trim();
            }

            document.getElementById('outputText').innerText = result;
        }

        function clearAll() {
            document.getElementById('inputText').value = '';
            document.getElementById('outputText').innerText = 'Kết quả hiển thị tại đây...';
        }

        function copyResult() {
            const text = document.getElementById('outputText').innerText;
            if (text && text !== 'Kết quả hiển thị tại đây...') {
                const el = document.createElement('textarea');
                el.value = text;
                document.body.appendChild(el);
                el.select();
                document.execCommand('copy');
                document.body.removeChild(el);
                const toast = document.getElementById('toast');
                toast.style.opacity = '1';
                setTimeout(() => toast.style.opacity = '0', 2000);
            }
        }
    </script>
</body>
</html>

