                            nextJunkIdx = j;
                            break;
                        }
                    }

                    if (nextJunkIdx !== -1) {
                        while (i < lines.length) {
                            let checkLine = lines[i].trim().toLowerCase();
                            if (checkLine === "" || keywords.some(k => checkLine === k || checkLine.includes(k))) {
                                i++;
                            } else {
