            // 3. Xóa số lẻ ở cuối dòng (1, 2, 99, 99+)
            if (options.removeEndNumbers) {
                line = line.replace(/\s+\d+(\+)?\s*$/, '');
            }

            finalLines.push(line);
            i++;
        }

        let result = finalLines.join('\n');

        // 4. Chuyển đổi số lớn sang chữ (Tỷ / Triệu / Nghìn / Trăm / Chục)
        if (options.convertLargeNumbers) {
            // Xử lý Tỷ: 1.000.000.000 hoặc 1000000000
            result = result.replace(/(\d+)(?:\.000){3}(?!\d)/g, '$1 tỷ');
            result = result.replace(/(\d+)000000000(?!\d)/g, '$1 tỷ');

            // Xử lý Triệu: 1.000.000 hoặc 1000000
            result = result.replace(/(\d+)(?:\.000){2}(?!\d)/g, '$1 triệu');
            result = result.replace(/(\d+)000000(?!\d)/g, '$1 triệu');

            // Xử lý Nghìn: 500.000 hoặc 500000
            result = result.replace(/(\d+)\.000(?!\d)/g, '$1 nghìn');
            result = result.replace(/(\b\d+)000\b/g, '$1 nghìn');

            // Xử lý Trăm: 100, 200...
            result = result.replace(/(\b\d+)00\b/g, '$1 trăm');

            // Xử lý Chục: 10, 20...90
            result = result.replace(/(\b[1-9])0\b/g, '$1 chục');
        }

        // Loại bỏ TẤT CẢ số (Chỉ thực hiện sau khi đã chuyển đổi số lớn nếu có)
        if (options.removeNumbers) {
