    const [inputText, setInputText] = useState('');
    const [outputText, setOutputText] = useState('');
    const [junkKeywords, setJunkKeywords] = useState('comment, 0 comment, Vote, SEND GIFT, bình luận, 0 bình luận, bỏ phiếu, gửi quà tặng, gửI quà tặng');

    const [options, setOptions] = useState({
        removeJunkBlocks: true,
        removeChapterHeader: true,
        removeEndNumbers: true,
        convertLargeNumbers: true,
        removeNumbers: false,
        removeWhitespace: true
    });

    const [toast, setToast] = useState(false);

    const handleOptionChange = (key: keyof typeof options) => {
        setOptions(prev => ({ ...prev, [key]: !prev[key] }));
    };

    // Thuật toán chuyển số sang chữ tiếng Việt
    const numberToVietnamese = (numStr: string): string => {
        const units = ["không", "một", "hai", "ba", "bốn", "năm", "sáu", "bảy", "tám", "chín"];
        const groups = ["", "nghìn", "triệu", "tỷ", "nghìn tỷ", "triệu tỷ", "tỷ tỷ"];

        const readThreeDigits = (n: string, isFull: boolean) => {
            let res = "";
            const a = parseInt(n[0]);
            const b = parseInt(n[1]);
            const c = parseInt(n[2]);

            if (isFull || a !== 0) {
                res += units[a] + " trăm ";
                if (b === 0 && c !== 0) res += "lẻ ";
            }

            if (b !== 0 && b !== 1) {
                res += units[b] + " mươi ";
                if (b !== 0 && c === 1) res += ""; // Sẽ xử lý mốt ở dưới
            } else if (b === 1) {
                res += "mười ";
            }

            if (c !== 0) {
                if (c === 1 && b > 1) res += "mốt";
                else if (c === 5 && b > 0) res += "lăm";
                else res += units[c];
            } else if (res === "" && c === 0) {
                // Không đọc gì
            } else if (b !== 0 && c === 0) {
                // Đã đọc mươi/mười rồi
            }

            return res.trim();
        };

        let cleanNum = numStr.replace(/\./g, "");
        if (isNaN(parseInt(cleanNum))) return numStr;

        if (parseInt(cleanNum) === 0) return "không";

        let result = "";
        let pos = cleanNum.length;
        let groupIdx = 0;

        while (pos > 0) {
            let len = Math.min(3, pos);
            let part = cleanNum.substring(pos - len, pos).padStart(3, '0');
            let partText = readThreeDigits(part, pos > 3);

            if (partText !== "") {
                result = partText + " " + groups[groupIdx] + " " + result;
            }

            pos -= len;
            groupIdx++;
        }

        return result.trim().replace(/\s+/g, ' ');
    };

    const processText = () => {
        if (!inputText.trim()) return;

        let lines = inputText.split(/\r?\n/);
        const keywords = junkKeywords.split(',').map(k => k.trim().toLowerCase()).filter(k => k !== "");

        let finalLines: string[] = [];
        let i = 0;

        while (i < lines.length) {
            let line = lines[i];
            let lineTrimmed = line.trim();
            let lineLower = lineTrimmed.toLowerCase();

            // 1. Xóa Chapter/Chương
            if (options.removeChapterHeader) {
                const chapterPattern = /^(chapter|chương)\s+\d+/i;
                if (chapterPattern.test(lineTrimmed)) {
                    i++;
                    continue;
                }
            }

            // 2. Xóa khối rác liên tiếp
            if (options.removeJunkBlocks) {
                let isCurrentJunk = keywords.some(k => lineLower === k || lineLower.includes(k));

                if (isCurrentJunk) {
                    let nextJunkIdx = -1;
                    for (let j = i + 1; j < Math.min(i + 6, lines.length); j++) {
                        let nextLineLower = lines[j].trim().toLowerCase();
                        if (nextLineLower === "") continue; 
                        if (keywords.some(k => nextLineLower === k || nextLineLower.includes(k))) {
                            nextJunkIdx = j;
                            break;
                        }
