                            }
                        }
                        continue;
                    }
                }
            }

            // 3. Xóa số lẻ ở cuối dòng (1, 2, 99, 99+)
            if (options.removeEndNumbers) {
                line = line.replace(/\s+\d+(\+)?\s*$/, '');
            }

