        // Loại bỏ TẤT CẢ số còn lại nếu option được bật
        if (options.removeNumbers) {
            result = result.replace(/[0-9]/g, '');
        }

        // Dọn dẹp văn bản
        if (options.removeWhitespace) {
            result = result.replace(/[^\S\r\n]+/g, ' ') 
                           .replace(/^\s*[\r\n]/gm, '') 
                           .trim();
        }

        setOutputText(result);
