import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse } from '@google/genai';
import { keyManager } from '../services/keyManager';
import { Loader } from './Loader';

interface Message {
    role: 'user' | 'model';
    text: string;
}

export const WebFrame: React.FC = () => {
    // Web Browser State
    const [viewMode, setViewMode] = useState<'browser' | 'gemini'>('gemini');
    const [urlInput, setUrlInput] = useState('https://www.wikipedia.org');
    const [currentUrl, setCurrentUrl] = useState('https://www.wikipedia.org');

    // Gemini Chat State
    const [messages, setMessages] = useState<Message[]>([
        { role: 'model', text: 'Xin chào! Tôi là Gemini 3 Pro. Tôi đã được tích hợp trực tiếp vào hệ thống PUCH. Bạn cần tôi hỗ trợ gì hôm nay?' }
    ]);
    const [input, setInput] = useState('');
    const [isThinking, setIsThinking] = useState(false);
    const chatEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        if (viewMode === 'gemini') scrollToBottom();
    }, [messages, isThinking, viewMode]);

    const handleGo = (e: React.FormEvent) => {
        e.preventDefault();
        let targetUrl = urlInput.trim();
        if (!targetUrl.startsWith('http://') && !targetUrl.startsWith('https://')) {
            targetUrl = 'https://' + targetUrl;
        }
        setCurrentUrl(targetUrl);
    };

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isThinking) return;

        const userText = input.trim();
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userText }]);
        setIsThinking(true);

        const apiKey = keyManager.getKey('image_video'); // Dùng key Gemini ở hàng 2
        if (!apiKey) {
            setMessages(prev => [...prev, { role: 'model', text: '⚠️ Lỗi: Chưa tìm thấy API Key ở Hàng 2 trong phần Cấu hình.' }]);
            setIsThinking(false);
            return;
        }

        try {
            const ai = new GoogleGenAI({ apiKey });
            // Cấu hình chat với lịch sử
            const history = messages.map(m => ({
                role: m.role,
                parts: [{ text: m.text }]
            }));

            const responseStream = await ai.models.generateContentStream({
                model: 'gemini-3-pro-preview',
                contents: [...history, { role: 'user', parts: [{ text: userText }] }],
                config: {
                    temperature: 0.7,
                    topP: 0.95,
                    topK: 64,
                }
            });

            let fullResponse = "";
            setMessages(prev => [...prev, { role: 'model', text: "" }]);

            for await (const chunk of responseStream) {
                const chunkText = chunk.text;
                fullResponse += chunkText;
                setMessages(prev => {
                    const newMsgs = [...prev];
                    newMsgs[newMsgs.length - 1].text = fullResponse;
                    return newMsgs;
                });
            }
        } catch (error: any) {
            setMessages(prev => [...prev, { role: 'model', text: `❌ Lỗi kết nối: ${error.message}` }]);
        } finally {
            setIsThinking(false);
        }
    };

    const clearChat = () => {
        setMessages([{ role: 'model', text: 'Lịch sử chat đã được làm mới. Tôi có thể giúp gì cho bạn?' }]);
    };

    return (
        <div className="max-w-7xl mx-auto glass-effect p-4 md:p-8 rounded-[40px] animate-rgb-border shadow-2xl flex flex-col h-[85vh]">

            {/* Control Bar */}
            <div className="mb-6 flex flex-col lg:flex-row items-center gap-6">
                {/* View Mode Switcher */}
                <div className="flex p-1 bg-black/40 rounded-2xl border border-white/5 w-full lg:w-auto">
                    <button 
                        onClick={() => setViewMode('gemini')} 
                        className={`flex items-center gap-2 px-6 py-2.5 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${viewMode === 'gemini' ? 'bg-pink-600 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}
                    >
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                        Gemini Pro
                    </button>
                    <button 
                        onClick={() => setViewMode('browser')} 
                        className={`flex items-center gap-2 px-6 py-2.5 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${viewMode === 'browser' ? 'bg-blue-600 text-white shadow-lg' : 'text-white/40 hover:text-white'}`}
                    >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M21 12a9 9 0 01-9 9m9-9a9 9 0 00-9-9m9 9H3m9 9a9 9 0 01-9-9m9 9c1.657 0 3-4.03 3-9s-1.343-9-3-9m0 18c-1.657 0-3-4.03-3-9s1.343-9 3-9m-9 9a9 9 0 019-9"></path></svg>
                        Trình duyệt
                    </button>
                </div>

                {viewMode === 'browser' ? (
                    <div className="flex-grow w-full flex items-center gap-3">
                        <form onSubmit={handleGo} className="relative flex-grow group">
                            <div className="absolute inset-y-0 left-5 flex items-center pointer-events-none">
                                <svg className="w-4 h-4 text-blue-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1"></path></svg>
                            </div>
                            <input 
                                type="text" 
                                value={urlInput}
                                onChange={(e) => setUrlInput(e.target.value)}
                                className="w-full bg-black/60 border border-white/10 rounded-2xl py-3.5 pl-12 pr-4 text-xs text-gray-200 focus:border-blue-500/50 outline-none transition-all shadow-inner"
                            />
                        </form>
                        <button onClick={handleGo} className="px-8 py-3.5 bg-blue-600 hover:bg-blue-500 text-white text-[10px] font-black uppercase rounded-2xl transition-all shadow-xl active:scale-95 tracking-widest">GỬI</button>
                    </div>
                ) : (
                    <div className="flex-grow flex justify-end">
                        <button onClick={clearChat} className="px-6 py-2.5 bg-white/5 border border-white/10 hover:bg-white/10 text-gray-400 hover:text-white text-[9px] font-black uppercase rounded-xl transition-all active:scale-95 tracking-widest">Làm mới đoạn chat</button>
                    </div>
                )}
            </div>

            {/* Display Area */}
            <div className="flex-grow bg-black/80 rounded-[2.5rem] border border-white/5 overflow-hidden relative shadow-[inset_0_2px_20px_rgba(0,0,0,0.8)] flex flex-col">
                {viewMode === 'browser' ? (
                    <>
                        <iframe 
                            src={currentUrl} 
                            className="w-full h-full border-none bg-white"
                            title="Web View Content"
                            sandbox="allow-same-origin allow-scripts allow-forms"
                        />
                        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 px-4 py-2 bg-black/60 backdrop-blur-md rounded-full border border-white/10 pointer-events-none">
                            <p className="text-[8px] font-black uppercase tracking-widest text-gray-500">
                                Lưu ý: Nhiều trang web lớn (Google, Facebook...) chặn việc nhúng Iframe.
                            </p>
                        </div>
                    </>
                ) : (
                    <div className="flex flex-col h-full">
                        {/* Chat History */}
                        <div className="flex-grow overflow-y-auto p-6 md:p-10 space-y-6 no-scrollbar">
                            {messages.map((msg, idx) => (
                                <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
                                    <div className={`max-w-[85%] md:max-w-[70%] p-5 rounded-3xl ${msg.role === 'user' ? 'bg-pink-600/20 border border-pink-500/20 text-pink-100 rounded-tr-none' : 'bg-white/5 border border-white/10 text-gray-300 rounded-tl-none'}`}>
                                        <div className="flex items-center gap-2 mb-2">
                                            <span className={`text-[8px] font-black uppercase tracking-widest ${msg.role === 'user' ? 'text-pink-400' : 'text-teal-400'}`}>
                                                {msg.role === 'user' ? 'YOU' : 'GEMINI 3 PRO'}
                                            </span>
                                        </div>
                                        <p className="text-sm leading-relaxed whitespace-pre-wrap font-medium">
                                            {msg.text || (isThinking && idx === messages.length - 1 ? '...' : '')}
                                        </p>
                                    </div>
                                </div>
                            ))}
                            {isThinking && messages[messages.length-1].role === 'user' && (
                                <div className="flex justify-start">
                                    <div className="bg-white/5 border border-white/10 p-5 rounded-3xl rounded-tl-none">
                                        <Loader />
                                    </div>
                                </div>
                            )}
                            <div ref={chatEndRef} />
                        </div>

                        {/* Chat Input */}
                        <div className="p-6 bg-black/40 border-t border-white/5">
                            <form onSubmit={handleSendMessage} className="relative">
                                <input 
                                    type="text"
                                    value={input}
                                    onChange={(e) => setInput(e.target.value)}
                                    placeholder="Hỏi bất cứ điều gì..."
                                    className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-6 pr-32 text-sm text-gray-200 focus:border-pink-500/50 outline-none transition-all"
                                />
                                <button 
                                    type="submit"
                                    disabled={!input.trim() || isThinking}
                                    className="absolute right-2 top-2 bottom-2 px-6 bg-pink-600 hover:bg-pink-500 disabled:opacity-20 text-white text-[10px] font-black uppercase rounded-xl transition-all shadow-lg active:scale-95"
                                >
                                    GỬI TIN
                                </button>
                            </form>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

