                    if (val >= 1000000 && val % 1000000 === 0) return (val / 1000000) + " triệu";
                    if (val >= 1000 && val % 1000 === 0) return (val / 1000) + " nghìn";
                }

                return numberToVietnamese(match);
            });
        }

