                <input type="file" accept="audio/*" onChange={handleFileChange} className="text-white" />
            </div>
            {error && <div className="text-red-500 mb-4">{error}</div>}
            {isTranscribing && <Loader />}
            {srtResult && (
                <div className="bg-gray-700 p-4 rounded-lg w-full overflow-auto max-h-96">
                    <pre className="text-white break-words">{srtResult}</pre>
                    <button
                        onClick={() => {
                            const blob = new Blob([srtResult], { type: 'text/plain' });
                            const url = URL.createObjectURL(blob);
                            const link = document.createElement('a');
                            link.href = url;
                            link.download = `${audioFile?.name.split('.').slice(0, -1).join('.') || 'audio'}.srt`;
                            document.body.appendChild(link);
                            link.click();
                            document.body.removeChild(link);
                            URL.revokeObjectURL(url);
                        }}
                        className="mt-2 px-4 py-2 bg-blue-500 hover:bg-blue-700 text-white rounded"
                    >
                        Download SRT
                    </button>
                </div>
            )}
            </div>
        );
    };
    ]]></content>
  </change>
